item.content:encoded:
/*Icons style */
.icon-style	img{
	 background: var(--nv-secondary-accent);
  padding: 16px;
}

/* Style the field labels */

div.wpforms-container-full .wpforms-form .wpforms-field-label {
    display: block;
    font-weight: 400;
    font-size: 16px;
    float: none;
    line-height: 1.3;
    margin: 0 0 4px 0;
    padding: 0;
  color:white;
}

/* Change the color of the required mark */
div.wpforms-container-full .wpforms-form .wpforms-required-label{color:#fff;}

/* Style the text area */

div.wpforms-container-full .wpforms-form .wpforms-field.wpforms-field-textarea textarea, div.wpforms-container-full .wpforms-form .wpforms-field.wpforms-field-textarea input {
    background-color: white;
    box-sizing: border-box;
    border-radius:0px;
    color: #333;
    -webkit-box-sizing: border-box;
    -moz-box-sizing: border-box;
    display: block;
    float: none;
    font-size: 16px;
    border: none;
    padding: 5px 10px;
    height: 120px;
    width: 100%;
    line-height: 1.3;
}


/* Style the text and email inputs */
div.wpforms-container-full .wpforms-form input[type=text], div.wpforms-container-full .wpforms-form input[type=email]{

	 background-color: white;
    box-sizing: border-box;
    border-radius:0px;
    color: #333;
    -webkit-box-sizing: border-box;
    -moz-box-sizing: border-box;
    display: block;
    float: none;
    font-size: 16px;
    border: none;
    padding: 5px 10px;
    height: 60px;
    width: 100%;
    line-height: 1.3;
}

/* Style the submit button */
div.wpforms-container-full .wpforms-form input[type=submit], div.wpforms-container-full .wpforms-form button[type=submit], div.wpforms-container-full .wpforms-form .wpforms-page-button {
		background-color: var(--nv-primary-accent);
    border: none;
    color: #fff;
    font-size: 0.9em;
		text-transform:uppercase;
		font-weight:600;
    padding: 15px 25px;

}

div.wpforms-container-full .wpforms-form input[type=submit]:hover, div.wpforms-container-full .wpforms-form input[type=submit]:focus, div.wpforms-container-full .wpforms-form input[type=submit]:active, div.wpforms-container-full .wpforms-form button[type=submit]:hover, div.wpforms-container-full .wpforms-form button[type=submit]:focus, div.wpforms-container-full .wpforms-form button[type=submit]:active, div.wpforms-container-full .wpforms-form .wpforms-page-button:hover, div.wpforms-container-full .wpforms-form .wpforms-page-button:active, div.wpforms-container-full .wpforms-form .wpforms-page-button:focus {
		background-color: var(--nv-secondary-accent);
    border: none;
    color: #121212;
    font-size: 0.9em;
		text-transform: uppercase;
		font-weight:600;
    padding: 15px 25px;

}

div.wpforms-container-full .wpforms-form input[type=submit]:hover, div.wpforms-container-full .wpforms-form input[type=submit]:focus, div.wpforms-container-full .wpforms-form input[type=submit]:active, div.wpforms-container-full .wpforms-form button[type=submit]:hover, div.wpforms-container-full .wpforms-form button[type=submit]:focus, div.wpforms-container-full .wpforms-form button[type=submit]:active, div.wpforms-container-full .wpforms-form .wpforms-page-button:hover, div.wpforms-container-full .wpforms-form .wpforms-page-button:active, div.wpforms-container-full .wpforms-form .wpforms-page-button:focus{
  border: none;
}

 .nv-single-page-wrap{
	margin-bottom: 0px;
}

/****GERAL****/

/***Titulo***/
.entry-title {
	border-bottom-width: 1px;
	border-bottom-style: solid;
}

/***Tituloh2***/
.uagb-section__inner-wrap h2 {
	border-bottom-width: 1px;
	border-bottom-style: solid;
}

/**Rodapé-fundo-cor**/
.footer-adv-overlay {
	background-color: rgb(88, 32, 105);
	background-image: linear-gradient(-225deg,#4B0082 45%, #7353BA 79%, #ceb0e0 100%, transparent, transparent);
}
/********************/
/*******DESKTOP*******/
/********************/
@media screen and (min-width: 1000px)
{
/**logo**/
	.custom-logo {
	position: absolute;
	right: 79%;
	top: 32%
}
/**Cabeçalho-cor-fundo**/
.main-header-bar {
	background-color: rgb(88, 32, 105);
	background-image: linear-gradient(-225deg, #FFFAFA 30%, #4B0082 30%, #7353BA 79%, #ceb0e0 100%, transparent, transparent);
}
/**Cabeçalho-Cor-letras**/
.main-header-menu a, .ast-header-custom-item a {
    color: #ffffff;
 }
/**Cabeçalho-menu-letras**/
#primary-menu {
	color: rgb(255, 255, 255);
	font-size: 16px;
	font-weight: normal;
	text-transform: uppercase;
	letter-spacing: 1px;
	padding: 16px;
}
/**Cabeçalho-cor-grifo-letras**/
.main-header-menu li:hover{
	border-bottom: 2px solid #fff; 
}
/**Rodapé-titulo**/
	.widget-title {
	position: relative;
	top: 5px;
}
/**Rodapé-corpo-text**/
 #text-3 p {
	font-family: roboto;
	font-size:  16px;
	text-align: justify;
	width: 320%;
	position: relative;
	top: 28px;
}
/***Rodapé-Menu***/
	#menu-menu-secundario a {
	font-family: roboto;
	font-size: 17px;
	position: relative;
	top: 3px;

}
}
/**Rodapé-redes-sociais**/
#astra-widget-social-profiles-5 .widget-title {
	font-family: Roboto;
	font-size: 23px;
	width: 100%;
	position: relative;
	top: 247px;
	right: 230%;


}
/**Rodapé-recoll**/
	#text-18 p {
	font-family: Roboto;
	font-size: 15px;
	width: 440%;
	position: relative;
	top: 440px;
	right: 350%;
	border-top: 1px solid rgb(255, 255, 255);
}
/********************/
/********************/
/*******TABLET*******/
/********************/
/********************/


@media screen and (max-width: 495px) and (min-width: 431px){
/**logo**/
.custom-logo {
	position: relative;
	right:30px;
	top:6px;
	background-color: white;
	padding: 10px;	
	}

}
@media screen and (max-width: 504px) and (min-width: 496px){
/**logo**/
