}
	/**Cabeçalho-Cor-letras**/
    .main-header-menu a, .ast-header-custom-item a {
        color: #ffffff;
     }
/**Cabeçalho-menu-letras**/
#primary-menu {
	color: rgb(255, 255, 255);
