}
	/**Rodapé-recoll**/
	#text-18 p {
	font-family: Roboto;
	font-size: 15px;
	position: static;
	text-align: justify;
	width: 100%;
	border-top: 1px solid rgb(255, 255, 255);

	}
	/**Rodapé-recoll-corpo-text-responsivo**/
.footer-adv-widget-2{
	width: 100%;
	}
  }
