@media screen and (max-width: 430px){
/**logo**/
.custom-logo {
	position: relative;
	top: 55%;
}
.menu-toggle {
	width: 55px !important;
	height: 55px !important;
	border-width: 4px !important;
	position: relative !important;
	top: 12px !important;
	right: 1px !important;
}

	.menu-toggle-icon {
	border-top-width: 4px;
	border-bottom-width: 4px;
	border-style: solid;
	position: relative;
	bottom: 2px;
}
/**Cabeçalho-cor-fundo**/

	/**Cabeçalho-Cor-letras**/
.main-header-menu a, .ast-header-custom-item a {
    color: #4B0082;
 }
/**Cabeçalho-cor-grifo-letras**/
.main-header-menu li:hover{
	border-bottom: 2px solid #fff; 
}
/**Cabeçalho-menu-letras**/
#primary-menu {
	color: rgb(255, 255, 255);
	font-size: 17px;
	font-weight: normal;
	text-transform: uppercase;
	letter-spacing: 1px;
	padding: 17px;
}
/**Rodapé-corpo-text**/
	#text-3 p {
